/**
 * cfft() - 快速傅里叶变换核心算法
 * ================================================================
 * 功能：对复数数组执行 FFT 变换（8192/16384 点等大规模变换）
 * 
 * 参数：
 *   @_ptr   : 指向复数结构体数组的指针（输入输出同一数组）
 *   @FFT_N  : FFT 点数（必须是 2 的幂）
 * 
 * 返回值：void（原地变换）
 * 
 * 工作流程：
 *   1. 位反序排列 - 重排输入序列以适配蝶形运算
 *   2. 蝶形运算 - log₂(N) 级，每级包含多个蝶形单元
 *   3. 旋转因子 - 从预计算的 sintab/costab 表中查取
 * 
 * 算法复杂度：O(N log₂ N)
 * ================================================================
 */
void cfft(struct compx *_ptr, uint32_t FFT_N)
{
    float32_t TempReal1, TempImag1, TempReal2, TempImag2;
    uint32_t k, i, j, z;
    uint32_t Butterfly_NoPerColumn;    /* 每级运算中的蝶形组数 */
    uint32_t Butterfly_NoOfGroup;      /* 当前处理的组索引 */
    uint32_t Butterfly_NoPerGroup;     /* 每组内的蝶形运算次数 */
    uint32_t ButterflyIndex1, ButterflyIndex2, P, J;
    uint32_t L;
    uint32_t M;

    /* --- 第一部分：位反转置换 (码位倒序) --- */
    /* 目的：将自然顺序的输入序列重新排列，以适应原位运算的蝶形结构 */
    z = FFT_N / 2; 
    
    for (i = 0, j = 0; i < FFT_N - 1; i++)        
    {
        /* 如果 i < j，则交换位置。
           i < j 确保每对元素只交换一次，防止交换后再交换回来。
        */
        if (i < j)                                     
        {                                           
            TempReal1 = _ptr[j].real;              
            _ptr[j].real = _ptr[i].real;
            _ptr[i].real = TempReal1;
            
            /* 注意：若输入为复数，虚部也需要对应交换（此处原代码仅处理了实部，
               建议根据实际 compx 定义补充虚部交换逻辑，如下所示） */
            TempImag1 = _ptr[j].imag;
            _ptr[j].imag = _ptr[i].imag;
            _ptr[i].imag = TempImag1;
        }
         
        /* 计算下一个位反转序的索引 j */
        k = z;                                     
        while (k <= j)                             
        {           
            j = j - k;                             
            k = k / 2;                             
        }
        j = j + k;                                 
    }
    
    /* --- 第二部分：蝶形运算阶段 --- */
    /* M 为总级数，例如 N=1024 时 M=10 */
    M = (uint32_t)log2(FFT_N);
    
    /* 初始化：第一级运算中，总点数 N 会分成 N/2 个组，每组包含 1 个蝶形 */
    Butterfly_NoPerColumn = FFT_N;                           
    Butterfly_NoPerGroup = 1;   

    for (L = 0; L < M; L++)                                
    {
        /* 每进入一级，组数减半 */
        Butterfly_NoPerColumn >>= 1;        
        
        /* 遍历每一组 */
        for (Butterfly_NoOfGroup = 0; Butterfly_NoOfGroup < Butterfly_NoPerColumn; Butterfly_NoOfGroup++)
        {  
            /* 遍历组内的每一个蝶形单元 */
            for (J = 0; J < Butterfly_NoPerGroup; J++) 
            {  
                /* 计算参与蝶形运算的两个数据的索引 */
                ButterflyIndex1 = ((Butterfly_NoOfGroup * Butterfly_NoPerGroup) << 1) + J;
                ButterflyIndex2 = ButterflyIndex1 + Butterfly_NoPerGroup;
                
                /* 计算旋转因子 (Twiddle Factor) 的查表索引 P */
                P = J * Butterfly_NoPerColumn;              
                
                /* 旋转因子复数乘法：
                   (A + Bi) * (cos - i*sin) = (A*cos + B*sin) + (B*cos - A*sin)i
                   注意：此处使用了预先计算好的 sine 和 cosine 表 (costab, sintab)
                */
                TempReal2 = _ptr[ButterflyIndex2].real * costab[P] + _ptr[ButterflyIndex2].imag * sintab[P];
                TempImag2 = _ptr[ButterflyIndex2].imag * costab[P] - _ptr[ButterflyIndex2].real * sintab[P];
                
                TempReal1 = _ptr[ButterflyIndex1].real;
                TempImag1 = _ptr[ButterflyIndex1].imag;
                
                /* 蝶形组合：
                   X[k] = X_top + W * X_bottom
                   X[k + distance] = X_top - W * X_bottom 
                */
                _ptr[ButterflyIndex1].real = TempReal1 + TempReal2; 
                _ptr[ButterflyIndex1].imag = TempImag1 + TempImag2;
                _ptr[ButterflyIndex2].real = TempReal1 - TempReal2;
                _ptr[ButterflyIndex2].imag = TempImag1 - TempImag2;
            }
        } 
        
        /* 每级运算结束后，下一级的组内蝶形数量翻倍 */
        Butterfly_NoPerGroup <<= 1; 
    }
}
/**
 * PowerPhaseRadians_f32() - 计算功率和相位
 * ================================================================
 * 功能：计算 FFT 结果的幅度和相位，用于信号分析
 * 
 * 参数：
 *   @s             : 复数数组指针（FFT 结果）
 *   @_usFFTPoints  : FFT 点数
 *   @_uiCmpValue   : 比较阈值（用于过滤小幅度分量）
 * 
 * 返回值：void
 * 
 * 工作流程：
 *   1. 对每个频点计算模值：mag = √(real² + imag²)
 *   2. 计算相位：phase = atan2(imag, real)
 *   3. 小于阈值的分量相位设为 0
 *   4. 将相位从弧度转换为度数（×180/π）
 * 
 * 输出：
 *   - real : 幅度（模值）
 *   - imag : 相位（度数）或 0（如果幅度 < 阈值）
 * ================================================================
 */
void PowerPhaseRadians_f32(struct compx *s, uint16_t _usFFTPoints, float32_t _uiCmpValue)        
{
    float32_t lX, lY;
    uint32_t i;
    float32_t phase;
    float32_t mag;

    for (i = 0; i < _usFFTPoints; i++)
    {
        lX = s[i].real;    /* 获取实部 */
        lY = s[i].imag;    /* 获取虚部 */
        
        /* atan2f 计算的角度范围是 (-pi, pi]，单位为弧度 */
        phase = atan2f(lY, lX);                         
        
        /* 计算当前频率点的模值（幅值）：sqrt(real^2 + imag^2) */
        arm_sqrt_f32((float32_t)(lX * lX + lY * lY), &mag);   
        
        /* 幅值过滤逻辑： */
        if (_uiCmpValue > mag)
        {
            /* 如果幅值太小（视为噪声），则相位无意义，直接归零 */
            s[i].imag = 0;            
        }
        else
        {
            /* 如果幅值超过阈值，则将弧度转换为角度 (degree = rad * 180 / PI) */
            /* 注意：计算结果重新存回了 s[i].imag 中 */
            s[i].imag = phase * 180.0f / 3.1415926f;   
        }
    }
}
